  1→import { AIMessageChunk, isAIMessageChunk } from '@langchain/core/messages';
  2→import { randomUUID } from 'crypto';
  3→import { appendFile } from 'fs/promises';
  4→import path from 'path';
  5→import {
  6→  ALLOW_TOOL_INPUT,
  7→  ENodeName,
  8→  EToolName,
  9→  SUMMARIZED_TOOL_CALL_RESULT_NAMES,
 10→  TalkableAgents,
 11→} from '../../common/constant';
 12→import { IGenerativeUIPayload } from '../../common/generative-ui';
 13→import { log } from '../../logger';
 14→import { IGraphEvent } from '../agents.service';
 15→import {
 16→  extractTokenUsage,
 17→  extractToolError,
 18→  getToolArgs,
 19→  parseChunk,
 20→  resolveToolOutput,
 21→  tryJSONStringify,
 22→} from './utils';
 23→
 24→const STREAM_DEBUG = process.env.STREAM_DEBUG === 'true';
 25→const STREAM_DEBUG_INCLUDE_DATA = process.env.STREAM_DEBUG_INCLUDE_DATA === 'true';
 26→const TASK_TOOL_NAME = 'task';
 27→
 28→type StreamMetadata = Record<string, unknown>;
 29→type StreamSubagentInfo = { type: string; namespace: string };
 30→type StreamContext = {
 31→  run_id: string;
 32→  name: string;
 33→  data: Record<string, unknown>;
 34→  node: ENodeName | undefined;
 35→  metadata?: StreamMetadata;
 36→};
 37→
 38→export interface ToolInputState {
 39→  inputtingTool: string | undefined;
 40→  subagentNamespaces?: Record<string, string>;
 41→}
 42→
 43→function makeEvent<T>(
 44→  event: string,
 45→  node: ENodeName | undefined,
 46→  data?: T,
 47→  subagent?: StreamSubagentInfo,
 48→): IGraphEvent<T> {
 49→  return {
 50→    id: randomUUID(),
 51→    timestamp: performance.now(),
 52→    event,
 53→    node,
 54→    data,
 55→    ...(subagent ? { subagent_type: subagent.type, subagent_namespace: subagent.namespace } : {}),
 56→  };
 57→}
 58→
 59→function asString(value: unknown): string | undefined {
 60→  return typeof value === 'string' ? value : undefined;
 61→}
 62→
 63→function getRegisteredSubagentNamespaces(state: ToolInputState): Record<string, string> {
 64→  if (!state.subagentNamespaces) {
 65→    state.subagentNamespaces = {};
 66→  }
 67→  return state.subagentNamespaces;
 68→}
 69→
 70→function expandNamespaceToken(token: string): string[] {
 71→  const trimmed = token.trim();
 72→  if (!trimmed) {
 73→    return [];
 74→  }
 75→  if (!trimmed.includes(':')) {
 76→    return [trimmed];
 77→  }
 78→  const segmented = trimmed.match(/[a-zA-Z_]+:[^:|,]+/g);
 79→  return segmented?.length ? segmented.map(segment => segment.trim()).filter(Boolean) : [trimmed];
 80→}
 81→
 82→function extractNamespace(metadata?: StreamMetadata): string[] {
 83→  if (!metadata) {
 84→    return [];
 85→  }
 86→
 87→  const rawCandidates: unknown[] = [
 88→    metadata.namespace,
 89→    metadata.langgraph_path,
 90→    metadata.checkpoint_ns,
 91→  ];
 92→
 93→  const flattened = rawCandidates.flatMap(candidate => {
 94→    if (Array.isArray(candidate)) {
 95→      return candidate;
 96→    }
 97→    if (typeof candidate === 'string') {
 98→      return candidate.split(/[|,]/g);
 99→    }
100→    return [];
101→  });
102→
103→  const namespace = flattened
104→    .flatMap(value => (typeof value === 'string' ? expandNamespaceToken(value) : []))
105→    .map(segment => segment.trim())
106→    .filter(segment => segment && segment !== 'root');
107→
108→  return Array.from(new Set(namespace));
109→}
110→
111→export function getStreamSource(
112→  metadata?: StreamMetadata,
113→  fallbackNode?: ENodeName,
114→): { kind: 'main' | 'subagent'; key: string; label?: string; namespace?: string[] } {
115→  const namespace = extractNamespace(metadata);
116→  const subagentKey = namespace.find(segment => segment.startsWith('tools:'));
117→  const label = asString(metadata?.lc_agent_name) ?? fallbackNode;
118→
119→  if (subagentKey) {
120→    return {
121→      kind: 'subagent',
122→      key: subagentKey,
123→      label,
124→      namespace,
125→    };
126→  }
127→
128→  return {
129→    kind: 'main',
130→    key: 'main',
131→    label,
132→    namespace,
133→  };
134→}
135→
136→function getToolsNamespace(metadata?: StreamMetadata): string | undefined {
137→  return extractNamespace(metadata).find(segment => segment.startsWith('tools:'));
138→}
139→
140→function parseTaskSubagentType(input: string | undefined): string | undefined {
141→  if (!input) {
142→    return undefined;
143→  }
144→  try {
145→    const parsed = JSON.parse(input) as Record<string, unknown>;
146→    return typeof parsed.subagent_type === 'string' ? parsed.subagent_type : undefined;
147→  } catch {
148→    return undefined;
149→  }
150→}
151→
152→function registerTaskSubagentNamespace(
153→  toolName: string,
154→  data: Record<string, unknown>,
155→  metadata: StreamMetadata | undefined,
156→  state: ToolInputState,
157→): void {
158→  if (toolName !== TASK_TOOL_NAME) {
159→    return;
160→  }
161→
162→  const toolsNamespace = getToolsNamespace(metadata);
163→  const rawInput = ((data.input as { input?: string } | undefined)?.input) || undefined;
164→  const subagentType = parseTaskSubagentType(rawInput);
165→  if (!toolsNamespace || !subagentType) {
166→    return;
167→  }
168→  getRegisteredSubagentNamespaces(state)[toolsNamespace] = subagentType;
169→}
170→
171→function resolveSubagentInfo(
172→  metadata: StreamMetadata | undefined,
173→  state: ToolInputState,
174→): StreamSubagentInfo | undefined {
175→  const namespaceSegments = extractNamespace(metadata);
176→  for (const [registeredNamespace, subagentType] of Object.entries(getRegisteredSubagentNamespaces(state))) {
177→    const matchesRegisteredNamespace = namespaceSegments.some(
178→      segment => segment === registeredNamespace || segment.startsWith(`${registeredNamespace}:`),
179→    );
180→    if (matchesRegisteredNamespace) {
181→      return {
182→        type: subagentType,
183→        namespace: registeredNamespace,
184→      };
185→    }
186→  }
187→
188→  return undefined;
189→}
190→
191→function shouldEmitToolInputPreview(toolName: string | undefined): boolean {
192→  return !!toolName && ALLOW_TOOL_INPUT.includes(toolName as EToolName);
193→}
194→
195→function shouldSummarizeToolCallResult(toolName: string): boolean {
196→  return SUMMARIZED_TOOL_CALL_RESULT_NAMES.includes(toolName);
197→}
198→
199→function summarizeToolCallResult(text: string): string {
200→  if (text.length <= 100) {
201→    return text;
202→  }
203→
204→  return `${text.slice(0, 50)}\n...\n${text.slice(-50)}`;
205→}
206→
207→function createToolInputEvent(
208→  toolName: string,
209→  toolCallChunks: AIMessageChunk['tool_call_chunks'],
210→  node: ENodeName | undefined,
211→  subagent?: StreamSubagentInfo,
212→): IGraphEvent | undefined {
213→  if (!shouldEmitToolInputPreview(toolName)) {
214→    return undefined;
215→  }
216→
217→  return makeEvent(
218→    'tool-input',
219→    node,
220→    { name: toolName, input: getToolArgs(toolCallChunks) },
221→    subagent,
222→  );
223→}
224→
225→function writeStreamDebugLog(event: string, name: string, node: ENodeName | undefined, data: Record<string, unknown>): void {
226→  if (!STREAM_DEBUG) {
227→    return;
228→  }
229→
230→  const debugData = STREAM_DEBUG_INCLUDE_DATA
231→    ? data
232→    : {
233→      keys: Object.keys(data || {}).slice(0, 12),
234→      size: JSON.stringify(data || {}).length,
235→    };
236→  const debugInfo = JSON.stringify({ event, name, node, data: debugData });
237→  const debugPath = path.join(process.cwd(), 'DEBUG.txt');
238→  void appendFile(debugPath, debugInfo + '\n', 'utf-8');
239→}
240→
241→export function handleChainStart(
242→  name: string,
243→  node: ENodeName | undefined,
244→  subagent?: StreamSubagentInfo,
245→): IGraphEvent | undefined {
246→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
247→  return makeEvent('agent-start', node, name, subagent);
248→}
249→
250→export function handleChainEnd(
251→  name: string,
252→  node: ENodeName | undefined,
253→  subagent?: StreamSubagentInfo,
254→): IGraphEvent | undefined {
255→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
256→  return makeEvent('agent-end', node, name, subagent);
257→}
258→
259→export function handleChatModelStart(node: ENodeName | undefined, subagent?: StreamSubagentInfo): IGraphEvent | undefined {
260→  return makeEvent('assistant-start', node, node, subagent);
261→}
262→
263→export function handleChatModelEnd(
264→  node: ENodeName | undefined,
265→  data?: Record<string, unknown>,
266→  subagent?: StreamSubagentInfo,
267→): IGraphEvent | undefined {
268→  const usage = extractTokenUsage(data);
269→  return makeEvent('assistant-end', node, {
270→    node,
271→    ...(usage ? { usage } : {}),
272→  }, subagent);
273→}
274→
275→export function handleChatModelStream(
276→  data: { chunk: unknown },
277→  node: ENodeName | undefined,
278→  state: ToolInputState,
279→  subagent?: StreamSubagentInfo,
280→): IGraphEvent | undefined {
281→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
282→  if (!data.chunk || !isAIMessageChunk(data.chunk as any)) return undefined;
283→
284→  const chunk = data.chunk as AIMessageChunk;
285→  const { tool_call_chunks } = chunk;
286→  const { text, thinking, tool } = parseChunk(chunk);
287→
288→  if (tool) {
289→    state.inputtingTool = tool;
290→    return createToolInputEvent(tool, tool_call_chunks, node, subagent);
291→  }
292→
293→  if (state.inputtingTool && tool_call_chunks?.length) {
294→    return createToolInputEvent(state.inputtingTool, tool_call_chunks, node, subagent);
295→  }
296→
297→  if (text || thinking) {
298→    return makeEvent('assistant', node, { thinking, content: text }, subagent);
299→  }
300→
301→  return undefined;
302→}
