444→/**
445→ * 与 LangGraph 流事件一一对应的诊断日志，集中在 dispatch 层便于统一开关与格式。
446→ * 行为需与各 handler 分支条件一致（例如仅 TalkableAgents / 非 render-ui 时输出）。
447→ */
448→function logStreamDispatchEvent(event: string, ctx: StreamContext): void {
449→  const { name, data, node } = ctx;
450→  switch (event) {
451→    case 'on_chain_start':
452→      if (node && (TalkableAgents as string[]).includes(name)) {
453→        log('agent-start: ' + name);
454→      }
455→      break;
456→    case 'on_chain_end':
457→      if (node && (TalkableAgents as string[]).includes(name)) {
458→        log('agent-end: ' + name);
459→      }
460→      break;
461→    case 'on_chain_error':
462→      if (node && (TalkableAgents as string[]).includes(name)) {
463→        const err = (data as { error?: unknown }).error;
464→        const message = extractToolError(err) ?? tryJSONStringify(err) ?? 'Agent execution failed';
465→        log(`agent-error: ${name} - ${message}`);
466→      }
467→      break;
468→    case 'on_chat_model_start':
469→      log('chat-start: ' + node);
470→      break;
471→    case 'on_chat_model_end':
472→      log('chat-end: ' + node);
473→      break;
474→    case 'on_chat_model_error': {
475→      const err = (data as { error?: unknown }).error;
476→      const message = extractToolError(err) ?? tryJSONStringify(err) ?? 'Model invocation failed';
477→      log(`chat-error: ${node} - ${message}`);
478→      break;
479→    }
480→    case 'on_chain_stream': {
481→      const interrupts = (data as { chunk?: Record<string, unknown> }).chunk?.__interrupt__;
482→      if (!Array.isArray(interrupts) || interrupts.length === 0) {
483→        break;
484→      }
485→      const interrupt = interrupts[0] as { id?: string; value?: unknown };
486→      if (!interrupt?.value || typeof interrupt.value !== 'object') {
487→        break;
488→      }
489→      log(`render-ui interrupt: ${JSON.stringify(interrupt.value)}`);
490→      break;
491→    }
492→    case 'on_tool_start': {
493→      log(`tool-start: ${name}`);
494→      if (name !== EToolName.RenderUI) {
495→        const input = (data as { input: { input: string } }).input?.input;
496→        if (input !== undefined) {
497→          log(`tool-call(${name})`);
498→        }
499→      }
500→      break;
501→    }
502→    case 'on_tool_end': {
503→      if (name === EToolName.RenderUI) {
504→        break;
505→      }
506→      const { artifact } = (data as { output: { artifact: unknown; content: unknown } }).output;
507→      if (artifact instanceof Error) {
508→        log(`tool-call-result(${name}).error: ${artifact.message}`);
509→      } else {
510→        log(`tool-call-result(${name})`);
511→      }
512→      break;
513→    }
514→    case 'on_tool_error': {
515→      if (name === EToolName.RenderUI) {
516→        break;
517→      }
518→      const err = (data as { error?: unknown }).error;
519→      const message = extractToolError(err) ?? tryJSONStringify(err) ?? 'Tool execution failed';
520→      log(`tool-call-result(${name}).error: ${message}`);
521→      break;
522→    }
523→    default:
524→      break;
525→  }
526→}
527→
528→export function dispatchStreamEvent(
529→  event: string,
530→  ctx: StreamContext,
531→  state: ToolInputState,
532→): IGraphEvent | undefined {
533→  const { run_id, name, data, node, metadata } = ctx;
534→  const subagent = buildSubagentInfo(name, data, metadata, state);
535→
536→  // 默认关闭流式调试，避免敏感数据落盘与同步 IO 阻塞。
537→  writeStreamDebugLog(event, name, node, data);
538→  // logStreamDispatchEvent(event, ctx);
539→
540→  switch (event) {
541→    case 'on_chain_start':
542→      return handleChainStart(name, node, subagent);
543→    case 'on_chain_end':
544→      return handleChainEnd(name, node, subagent);
545→    case 'on_chain_error':
546→      return handleChainError(name, data as { error?: unknown }, node, subagent);
547→    case 'on_chat_model_start':
548→      return handleChatModelStart(node, subagent);
549→    case 'on_chat_model_end':
550→      return handleChatModelEnd(node, data, subagent);
551→    case 'on_chat_model_error':
552→      return handleChatModelError(node, data as { error?: unknown }, subagent);
553→    case 'on_chat_model_stream':
554→      return handleChatModelStream(data as { chunk: unknown }, node, state, subagent);
555→    case 'on_chain_stream':
556→      return handleChainStream(data as { chunk?: Record<string, unknown> }, node, subagent);
557→    case 'on_tool_start':
558→      return handleToolStart(
559→        run_id,
560→        name,
561→        data as { input: { input: string } },
562→        node,
563→        state,
564→        subagent,
565→      );
566→    case 'on_tool_end':
567→      return handleToolEnd(
568→        run_id,
569→        name,
570→        data as { output: { artifact: unknown; content: unknown } },
571→        node,
572→        subagent,
573→      );
574→    case 'on_tool_error':
575→      return handleToolError(
576→        run_id,
577→        name,
578→        data as { error?: unknown },
579→        node,
580→        subagent,
581→      );
582→    default:
583→      return undefined;
584→  }
585→}
